 65	struct timespec timespec_add(struct timespec lhs, struct timespec rhs)
 66	{
 67		struct timespec result;
 68	
 69		result.tv_sec = lhs.tv_sec + rhs.tv_sec;
 70		result.tv_nsec = lhs.tv_nsec + rhs.tv_nsec;
 71	
 72		if(result.tv_nsec > 1e9)
 73		{
 74			result.tv_sec++;
 75			result.tv_nsec-= 1e9;
 76		}
 77	
 78		return result;
 79	}
 80	
 81	struct timespec timespec_sub(struct timespec lhs, struct timespec rhs)
 82	{
 83		struct timespec result;
 84		if ((lhs.tv_nsec-rhs.tv_nsec)<0)
 85		{
 86			result.tv_sec = lhs.tv_sec-rhs.tv_sec-1;
 87			result.tv_nsec = 1000000000+lhs.tv_nsec-rhs.tv_nsec;
 88		}
 89		else
 90		{
 91			result.tv_sec = lhs.tv_sec-rhs.tv_sec;
 92			result.tv_nsec = lhs.tv_nsec-rhs.tv_nsec;
 93		}
 94		return result;
 95	}
